const project = $('Fetch Project').first().json;
const body = $('Webhook Trigger').first().json.body;
const meta = project.metadata || {};
const ev = meta.evidence || {};

const criteria = {
  brief_clarity: (ev.brief_clarity_score || 0) >= 7.0,
  feasibility_confirmed: !!ev.feasibility_note,
  no_conflicts: ev.conflict_check !== false,
  complexity_estimated: ['small', 'medium', 'large'].includes(ev.estimated_complexity)
};

const passed = Object.values(criteria).every(Boolean);
const failed = Object.entries(criteria).filter(([, v]) => !v).map(([k]) => k);

return [{
  json: {
    gateId: 'G0',
    projectId: body.projectId,
    runId: body.runId,
    passed,
    criteria,
    confidence: passed ? 85 : 40,
    reasoning: passed
      ? 'Intake criteria met: brief is clear, feasible, no conflicts'
      : 'Intake criteria not met: ' + failed.join(', ')
  }
}];

