const evalResult = $input.first().json;
const body = $('Webhook Trigger').first().json.body;
const now = new Date().toISOString();

return [{
  json: {
    ...evalResult,
    trace_id: `gate-${evalResult.gateId}-${body.runId}`,
    run_id: body.runId,
    project_id: body.projectId,
    issue_id: body.projectId,
    agent: 'gate-evaluator',
    status: evalResult.passed ? 'PASS' : 'FAIL',
    started_at: $('Webhook Trigger').first().json.headers?.['x-request-start'] || now,
    completed_at: now,
    latency_ms: Date.now() - new Date($('Webhook Trigger').first().json.headers?.['x-request-start'] || now).getTime(),
    error_code: evalResult.passed ? null : 'GATE_CRITERIA_NOT_MET',
    evidence_ref: `evidence/${evalResult.gateId}/${body.projectId}/${body.runId}`
  }
}];

const evidence = $('Build Evidence').first().json;
const hitlGates = ['G0', 'G1.5', 'G2', 'G4', 'G6', 'G7'];
const hitlRequired = hitlGates.includes(evidence.gateId);

let approvalTicketId = null;
try {
  const ticketResponse = $('Create Approval Ticket').first().json;
  approvalTicketId = ticketResponse.id || ticketResponse.issueId || null;
} catch (e) {
  approvalTicketId = null;
}

return [{
  json: {
    workflow: 'hive-gate-evaluator',
    endpoint: 'gate-evaluator',
    kind: 'deterministic',
    status: evidence.passed ? 'completed' : 'failed',
    receivedAt: evidence.started_at,
    completedAt: evidence.completed_at,
    timeoutMs: 30000,
    success: true,
    passed: evidence.passed,
    gateId: evidence.gateId,
    projectId: evidence.project_id,
    runId: evidence.run_id,
    confidence: evidence.confidence,
    reasoning: evidence.reasoning,
    criteria: evidence.criteria,
    evidence: {
      trace_id: evidence.trace_id,
      evidence_ref: evidence.evidence_ref,
      latency_ms: evidence.latency_ms
    },
    hitlRequired,
    approvalTicketId
  }
}];
